LOAD R1 c; 

LOAD R2 d; 

ADD R1 R1 R2; R1  R1 + R2 \Rightarrow R1 = c + d 

LOAD R2 e; 

SUB R2, R2, R1; R2  R2 - R1 R2 = e - (c + d) 

LOAD R1 a; 

LOAD R3 b; 

SUB R1, R1, R3; R1  R1 - R3 ; R1 = (a - b) 

ADD R3, R1, R2; R3 = (a - b) + [e - (c + d)] 
OR 

ADD R1 R1 R2; R1  R1 + R2 
OR 

ADD R2 R1 R2; R2  R1 + R2 


